mapper.sql:
WHERE n.deleted = 0

    AND (n.title LIKE CONCAT('%', #{keyword}, '%')
        OR n.content LIKE CONCAT('%', #{keyword}, '%'))


    AND n.status = #{status}


    AND n.type = #{type}

mapper.select:
SELECT
FROM sys_notice n LEFT JOIN sys_user u ON u.id = n.publisher_id AND u.deleted = 0
ORDER BY COALESCE(n.publish_time, n.created_at) DESC, n.id DESC LIMIT #{limit} OFFSET #{offset}
